import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import logo from "../assets/indiaadvertising-logo.png";
import { Menu, X, ChevronDown } from "lucide-react";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [activeSection, setActiveSection] = useState("Home");
  const [showProductsDropdown, setShowProductsDropdown] = useState(false);

  const navItems = [
    { name: "Home", id: "home" },
    { name: "About", id: "about" },
    { name: "Products", id: "products" },
    { name: "Gallery", id: "gallery" },
    { name: "Contact", id: "contact" }
  ];

  // Smooth scroll
  const scrollToSection = (id) => {
    setIsOpen(false);
    setShowProductsDropdown(false);
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth" });
  };

  // Scroll spy – highlight active menu
  useEffect(() => {
    const handleScroll = () => {
      navItems.forEach((item) => {
        const section = document.getElementById(item.id);
        if (section) {
          const rect = section.getBoundingClientRect();
          if (rect.top <= 120 && rect.bottom >= 120) {
            setActiveSection(item.name);
          }
        }
      });
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <motion.nav
      initial={{ y: -80 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.5 }}
      className="
        sticky top-0 z-50
        bg-white/70 backdrop-blur-xl
        border-b border-gray-200/40
        shadow-[0_2px_10px_rgba(0,0,0,0.05)]
      "
    >
      {/* MAIN NAV */}
      <div className="flex items-center justify-between h-16 px-4 mx-auto max-w-7xl">
        {/* Logo */}
        <motion.div whileHover={{ scale: 1.05 }}>
          <button onClick={() => scrollToSection("home")} className="flex items-center">
            <img src={logo} className="h-10" alt="Logo" />
          </button>
        </motion.div>

        {/* Desktop Menu */}
        <div className="items-center hidden space-x-6 md:flex">
          {navItems.map((item) => (
            <motion.button
              key={item.name}
              onClick={() => {
                if (item.name === "Products") {
                  setShowProductsDropdown(!showProductsDropdown);
                } else {
                  scrollToSection(item.id);
                }
              }}
              className={`
                relative px-3 py-2 text-sm font-medium transition 
                ${
                  activeSection === item.name
                    ? "text-yellow-600"
                    : "text-gray-700 hover:text-yellow-500"
                }
              `}
              whileHover={{ y: -2 }}
              whileTap={{ scale: 0.95 }}
            >
              {item.name}

              {/* Active Indicator */}
              {activeSection === item.name && (
                <motion.div
                  layoutId="activeIndicator"
                  className="absolute bottom-0 left-0 right-0 w-full h-[3px] bg-yellow-500 rounded-full"
                />
              )}
            </motion.button>
          ))}
        </div>

        {/* Mobile Burger */}
        <motion.button
          onClick={() => setIsOpen(!isOpen)}
          whileTap={{ scale: 0.9 }}
          className="p-2 text-gray-800 rounded-md md:hidden hover:bg-gray-100"
        >
          {isOpen ? <X size={26} /> : <Menu size={26} />}
        </motion.button>
      </div>

      {/* --- PRODUCTS DROPDOWN (DESKTOP) --- */}
      <AnimatePresence>
        {showProductsDropdown && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            className="absolute left-0 hidden w-full border-t shadow-xl  md:block bg-white/95 backdrop-blur-xl border-gray-200/40"
          >
            <div className="grid grid-cols-3 gap-6 p-6 mx-auto max-w-7xl">
              {/* 3D style product preview cards */}
              {[
                "Sign Boards",
                "LED Letters",
                "Acrylic Letters",
                "Name Plates",
                "ACP Signage",
                "World Maps"
              ].map((cat) => (
                <motion.div
                  key={cat}
                  className="p-4 transition border border-gray-200 rounded-lg shadow-sm cursor-pointer bg-gray-50 hover:bg-yellow-50 hover:shadow-md"
                  whileHover={{ scale: 1.02 }}
                  onClick={() => {
                    scrollToSection("products");
                    setShowProductsDropdown(false);
                  }}
                >
                  <h4 className="text-lg font-semibold text-gray-800">{cat}</h4>
                  <p className="mt-1 text-sm text-gray-600">
                    Explore {cat.toLowerCase()} starting at best price.
                  </p>
                </motion.div>
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* --- MOBILE MENU --- */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="shadow-lg md:hidden bg-white/90 backdrop-blur-xl"
          >
            <div className="p-4 space-y-2">
              {navItems.map((item) => (
                <motion.button
                  key={item.name}
                  onClick={() => scrollToSection(item.id)}
                  className="block w-full px-3 py-3 text-base font-medium text-gray-700 rounded-md  hover:bg-yellow-100 hover:text-yellow-700"
                  whileHover={{ x: 6 }}
                >
                  {item.name}
                </motion.button>
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.nav>
  );
};

export default Navbar;
